code = """import pandas as pd
import json
from datetime import datetime, timezone
import calendar

# Load stored query results
cases = var_call_9ZPUrR3ooNl1ZeW1KOgbATt2
order_items = var_call_aDNd9YjBBEjINakPulE0iHKl

# Normalize IDs helper
def norm_id(s):
    if s is None:
        return None
    return str(s).strip().lstrip('#').strip()

order_ids = set(norm_id(oi.get('Id')) for oi in order_items)

# Filter and count cases linked to those order items within date range
counts = {}
for c in cases:
    oid = norm_id(c.get('orderitemid__c'))
    if oid in order_ids:
        # parse createddate
        cd = c.get('createddate')
        try:
            # handle timezone offset by parsing and converting to naive UTC
            dt = datetime.fromisoformat(cd.replace('Z','+00:00'))
            dt = dt.astimezone(timezone.utc).replace(tzinfo=None)
        except Exception:
            # try generic parse
            dt = datetime.strptime(cd[:19], '%Y-%m-%dT%H:%M:%S')
        # consider only between 2020-06-01 and 2021-04-01
        if datetime(2020,6,1) <= dt and dt < datetime(2021,4,1):
            key = dt.strftime('%Y-%m')
            counts[key] = counts.get(key, 0) + 1

# Ensure all months in range are present (even with zero)
months = []
start = datetime(2020,6,1)
for i in range(10):
    # compute year and month correctly
    total_month = start.month - 1 + i
    y = start.year + total_month // 12
    m = total_month % 12 + 1
    ym = f"{y:04d}-{m:02d}"
    months.append(ym)
    if ym not in counts:
        counts[ym] = 0

# Prepare list of (ym, count, month_name)
data = []
for ym in months:
    y,m = ym.split('-')
    mon_name = calendar.month_name[int(m)]
    data.append((ym, counts.get(ym,0), mon_name))

# Compute mean and std
vals = [x[1] for x in data]
df = pd.Series(vals)
mean = float(df.mean())
std = float(df.std(ddof=0))

# Identify months significantly exceeding (mean + 2*std)
threshold = mean + 2*std
significant = [ (x[0], x[1], x[2]) for x in data if x[1] > threshold ]

# If none, return "None", else choose the one with highest count (if tie, latest)
if not significant:
    result = "None"
else:
    # sort by count desc then ym desc
    significant.sort(key=lambda x: (x[1], x[0]), reverse=True)
    result = significant[0][2]

print("__RESULT__:")
print(json.dumps(result))"""

